pub fn zmemcpy(dst: &mut [u8], src: &[u8], n: usize) {
    assert!(dst.len() >= n, "zmemcpy: dst too short ({} < {})", dst.len(), n);
    assert!(src.len() >= n, "zmemcpy: src too short ({} < {})", src.len(), n);
    dst[..n].copy_from_slice(&src[..n]);
}

pub fn zmemcmp(s1: &[u8], s2: &[u8], n: usize) -> i32 {
    assert!(s1.len() >= n, "zmemcmp: s1 too short ({} < {})", s1.len(), n);
    assert!(s2.len() >= n, "zmemcmp: s2 too short ({} < {})", s2.len(), n);
    for i in 0..n {
        if s1[i] != s2[i] {
            return (s1[i] as i32) - (s2[i] as i32);
        }
    }
    0
}

pub fn zmemzero(buffer: &mut [u8], len: usize) {
    assert!(buffer.len() >= len, "zmemzero: buffer too short ({} < {})", buffer.len(), len);
    for b in &mut buffer[..len] { *b = 0; }
}

pub fn byte_swap(word: u64) -> u64 {
    word.swap_bytes()
}

pub fn bi_reverse(mut code: u32, len: u8) -> u32 {
    let mut res: u32 = 0;
    for _ in 0..len {
        res = (res << 1) | (code & 1);
        code >>= 1;
    }
    res
}
